INSERT INTO literature (literatureId, title, author, abstract, languageId, institutionId, publication_year, doi_url, open_access_url, reference) VALUES
('727cce4c-f100-4b98-a891-cd48ee0d9512', 'Scaffold: Quantum Programming Language', 'Abhari et al.', NULL, '6ec32296-2ab0-488a-a2ea-472a28bb272d', '8a9b1c2d-3e4f-5a6b-7c8d-9e1f2a3b4c5d', 2012, NULL, 'https://apps.dtic.mil/sti/tr/pdf/ADA571279.pdf', 'Abhari, Ali J., et al. "Scaffold: Quantum programming language." (2012).'),
('684f1eef-2ddf-49ac-a34a-81058cb7efc0', 'Quantum programming languages', 'Heim et al.', 'Quantum programming languages are essential to translate ideas into instructions that can be executed by a quantum computer. Not only are they crucial to the programming of quantum computers at scale but also they can facilitate the discovery and development of quantum algorithms even before hardware exists that is capable of executing them. Quantum programming languages are used for controlling existing physical devices, for estimating the execution costs of quantum algorithms on future devices, for teaching quantum computing concepts, or for verifying quantum algorithms and their implementations. They are used by newcomers and seasoned practitioners, researchers and developers working on the next ground-breaking discovery or applying known concepts to real-world problems. This variety in purpose and target audiences is reflected in the design and ecosystem of the existing quantum programming languages, depending on which factors a language prioritizes. In this Review, we highlight important aspects of quantum programming and how it differs from conventional programming. We overview a selection of several state-of-the-art quantum programming languages, highlight their salient features, and provide code samples for each of the languages and Docker files to facilitate installation of the software packages.', NULL, NULL, 2020, 'https://www.nature.com/articles/s42254-020-00245-7', NULL, 'Heim, Bettina, et al. "Quantum programming languages." Nature Reviews Physics 2.12 (2020): 709-722.'),
('581cccc9-9848-4c65-8a3a-5b150f93e7e2', 'Towards a Hierarchical Quantum Circuit Language', 'Schober and Wesley', 'Many circuit-based quantum programming languages contain limited functionality for handling programs  with quantum branching events. In this paper we introduce a hierarchical circuit language with two new  connectives, one for generalized controlled operations and one for sub-circuit exponentiation, to reason  formally about such programs. We construct the hierarchical circuit language using a novel category-theoretic  construction, demonstrate that its compositional properties are non-trivial, show a circuit identity which may  be useful for circuit optimization by a compiler, demonstrate how generalized controlled operations describe  quantum control flow, and then contrast generalized controlled operations with Pauli rotations.', NULL, '5d6e7f8a-9b1c-2d3e-4f5a-6b7c8d9e1f2a', 2025, NULL, 'https://cqi.inf.usi.ch/publications/Hierarchical_PlanQC2026.pdf', 'Heim, Bettina, et al. "Quantum programming languages." Nature Reviews Physics 2.12 (2020): 709-722.'),
('04fce93e-a641-476f-a050-3a4fa1d8455b', 'Alternation in Quantum Programming: From Superposition of Data to Superposition of Programs', 'Ying et al.', 'We extract a novel quantum programming paradigm - superposition of programs from the design idea of a popular class of quantum algorithms, namely quantum walkbased algorithms. The generality of this paradigm is guaranteed by the universality of quantum walks as a computational model. A new quantum programming language QGCL is then proposed to support the paradigm of superposition of programs. This language can be seen as a quantum extension of Dijkstra’s GCL (Guarded Command Language). Surprisingly, alternation in GCL splits into two different notions in the quantum setting: classical alternation (of quantum programs) and quantum alternation, with the latter being introduced in QGCL for the first time. Quantum alternation is the key program construct for realizing the paradigm of superposition of programs. The denotational semantics of QGCL are defined by introducing a new mathematical tool called the guarded composition of operator-valued functions. Then the weakest precondition semantics of QGCL can straightforwardly derived. Another very useful program construct in realizing the quantum programming paradigm of superposition of programs, called quantum choice, can be easily defined in terms of quantum alternation. The relation between quantum choices and probabilistic choices is clarified through defining the notion of local variables. We derive a family of algebraic laws for QGCL programs that can be used in program verification, transformations and compilation. The expressive power of QGCL is illustrated by several examples where various variants and generalizations of quantum walks are conveniently expressed using quantum alternation and quantum choice. We believe that quantum programming with quantum alternation and choice will play an important role in further exploiting the power of quantum computing.', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2014, NULL, 'https://arxiv.org/pdf/1402.5172', 'Ying, Mingsheng, Nengkun Yu, and Yuan Feng. "Alternation in quantum programming: from superposition of data to superposition of programs." arXiv preprint arXiv:1402.5172 (2014).'),
('c82b9022-de1c-4259-8db6-40704e600077', 'Logical Reversibility of Computation', 'Bennett', 'The usual general-purpose computing automaton (e.g.. a Turing machine) is logically irreversible- its transition function lacks a single-valued inverse. Here it is shown that such machines may he made logically reversible at every step, while retainillg their simplicity and their ability to do general computations. This result is of great physical interest because it makes plausible the existence of thermodynamically reversible computers which could perform useful computations at useful speed while dissipating considerably lessthan kT of energyper logical step. In the first stage of itscomputationthe logically reversibleautomatonparallels the corresponding irreversible automaton, except that it saves all intermediate results, thereby avoiding the irreversible operation of erasure. The second stage consistsof printing out the desired output. Thethird stage then reversibly disposes of all the undesired intermediate results by retracing the steps of the first stage in backward order (a process which is only possible because the first stage has been carried out reversibly), thereby restoring the machine (except for the now-written output tape) toits original condition. The final machine configuration thus contains the desired output anda reconstructed copy o f the input, but no other undesired data. The foregoing results are demonstrated explicitly using a type of three-tape Turing machine. The biosynthesis of messenger RNA is discussed as a physical example of reversible computation.', NULL, NULL, 1973, 'https://ieeexplore.ieee.org/document/5391327', NULL, 'C. H. Bennett, "Logical Reversibility of Computation," in IBM Journal of Research and Development, vol. 17, no. 6, pp. 525-532, Nov. 1973, doi: 10.1147/rd.176.0525.'),
('3679f1a7-ad3e-4651-b189-f758c663ef6b', 'Quantum theory, the Church-Turing principle and the universal quantum computer', 'Deutsch', 'The usual general-purpose computing automaton (e.g.. a Turing machine) is logically irreversible- its transition function lacks a single-valued inverse. Here it is shown that such machines may he made logically reversible at every step, while retainillg their simplicity and their ability to do general computations. This result is of great physical interest because it makes plausible the existence of thermodynamically reversible computers which could perform useful computations at useful speed while dissipating considerably lessthan kT of energyper logical step. In the first stage of itscomputationthe logically reversibleautomatonparallels the corresponding irreversible automaton, except that it saves all intermediate results, thereby avoiding the irreversible operation of erasure. The second stage consistsof printing out the desired output. Thethird stage then reversibly disposes of all the undesired intermediate results by retracing the steps of the first stage in backward order (a process which is only possible because the first stage has been carried out reversibly), thereby restoring the machine (except for the now-written output tape) toits original condition. The final machine configuration thus contains the desired output anda reconstructed copy o f the input, but no other undesired data. The foregoing results are demonstrated explicitly using a type of three-tape Turing machine. The biosynthesis of messenger RNA is discussed as a physical example of reversible computation.', NULL, 'f628076d-f0e7-4df0-83db-28c9779a8ecf', 1985, '10.1098/rspa.1985.0070', 'https://royalsocietypublishing.org/rspa/article/400/1818/97/15743/Quantum-theory-the-Church-Turing-principle-and-the', 'David Deutsch; Quantum theory, the Church–Turing principle and the universal quantum computer. Proc. A 1 July 1985; 400 (1818): 97–117. https://doi.org/10.1098/rspa.1985.0070'),
('aa258e6a-7e0b-4838-a522-57b4dd25019f', 'Quantum computational networks', 'Deutsch', 'The theory of quantum computational networks is the quantum generalization of the theory of logic circuits used in classical computing machines. Quantum gates are the generalization of classical logic gates. A single type of gate, the universal quantum gate, together with quantum ‘unit wires’, is adequate for constructing networks with any possible quantum computational property.', NULL, 'f628076d-f0e7-4df0-83db-28c9779a8ecf', 1989, 'https://doi.org/10.1098/rspa.1989.0099', NULL, 'David Elieser Deutsch; Quantum computational networks. Proc. A 1 September 1989; 425 (1868): 73–90. https://doi.org/10.1098/rspa.1989.0099'),
('43bc12e0-e81b-4727-9e3c-3e54586e40e8', 'Rapid solution of problems by quantum computation', 'Deutsch and Jozsa', 'A class of problems is described which can be solved more efficiently by quantum computation than by any classical or stochastic method. The quantum computation solves the problem with certainty in exponentially less time than any classical deterministic computation.', NULL, 'f628076d-f0e7-4df0-83db-28c9779a8ecf', 1992, 'https://doi.org/10.1098/rspa.1992.0167', NULL, 'David Deutsch, Richard Jozsa; Rapid solution of problems by quantum computation. Proc. A 1 December 1992; 439 (1907): 553–558. https://doi.org/10.1098/rspa.1992.0167'),
('63a11174-05fa-4de7-8614-af75a5466777', 'Quantum Complexity Theory', 'Bernstein and Vazirani', NULL, NULL, '2f9752c5-a746-4484-8ad6-9aa35d62a70a', 1993, NULL, 'https://dl.acm.org/doi/10.1145/167088.167097', "Ethan Bernstein and Umesh Vazirani. 1993. Quantum complexity theory. In Proceedings of the twenty-fifth annual ACM symposium on Theory of Computing (STOC '93). Association for Computing Machinery, New York, NY, USA, 11–20. https://doi.org/10.1145/167088.167097"),
-- ('8840c04e-54f8-4506-8801-474197e95837', 'Quantum measurements and the Abelian Stabilizer Problem', 'Kitaev', 'We present a polynomial quantum algorithm for the Abelian stabilizer problem which includes both factoring and the discrete logarithm. Thus we extend famous Shor’s results [7]. Our method is based on a procedure for measuring an eigenvalue of a unitary operator. Another application of this procedure is a polynomial quantum Fourier transform algorithm for an arbitrary finite Abelian group. The paper also contains a rather detailed introduction to the theory of quantum computation.', NULL, '2f9752c5-a746-4484-8ad6-9aa35d62a70a', 2024, NULL, 'http://arxiv.org/abs/quant-ph/9511026', "arXiv:quant-ph/9511026"),
('4d67cae0-7330-4eab-9552-19de65e2dcd7', 'A fast quantum mechanical algorithm for database search', 'Grover', NULL, NULL, NULL, 1996, NULL, 'https://dl.acm.org/doi/10.1145/237814.237866', "Lov K. Grover. 1996. A fast quantum mechanical algorithm for database search. In Proceedings of the twenty-eighth annual ACM symposium on Theory of Computing (STOC '96). Association for Computing Machinery, New York, NY, USA, 212–219. https://doi.org/10.1145/237814.237866"),
('8a1daded-199e-4b2e-bc74-40a6aa8f16cd', 'Extending the Lambda Calculus to Express Randomized and Quantumized Algorithms', 'Maymin', 'This paper introduces a formal metalanguage called the lambda-q calculus for the specification of quantum programming languages. This metalanguage is an extension of the lambda calculus, which provides a formal setting for the specification of classical programming languages. As an intermediary step, we introduce a formal metalanguage called the lambdap calculus for the specification of programming languages that allow true random number generation. We demonstrate how selected randomized algorithms can be programmed directly in the lambda-p calculus. We also demonstrate how satisfiability can be efficiently solved in the lambda-q calculus.', NULL, "d9b1c8e7-5f3a-4c9b-9e5e-2a1f0c8e4b2a", 1997, NULL, 'http://arxiv.org/abs/quant-ph/9612052', "arXiv:quant-ph/9612052"),
('5ffb7f3c-4438-48a1-a629-097b41088476', 'Polynomial-Time Algorithms for Prime Factorization and Discrete Logarithms on a Quantum Computer', 'Shor', 'A digital computer is generally believed to be an efficient universal computing device; that is, it is believed able to simulate any physical computing device with an increase in computation time by at most a polynomial factor. This may not be true when quantum mechanics is taken into consideration. This paper considers factoring integers and finding discrete logarithms, two problems which are generally thought to be hard on a classical computer and which have been used as the basis of several proposed cryptosystems. Efficient randomized algorithms are given for these two problems on a hypothetical quantum computer. These algorithms take a number of steps polynomial in the input size, e.g., the number of digits of the integer to be factored.', NULL, NULL, 1996, NULL, 'http://arxiv.org/abs/quant-ph/9508027', "arXiv:quant-ph/9508027"),
('ad1c1c2e-577f-4ccf-8bf2-f96af5d483ab', 'The Halting Problem for Quantum Computers', 'Linden', 'We argue that the halting problem for quantum computers which was first raised by Myers, is by no means solved, as has been claimed recently. We explicitly demonstrate the difficulties that arise in a quantum computer when different branches of the computation halt at different, unknown, times.', NULL, NULL, 1998, NULL, 'http://arxiv.org/abs/quant-ph/9806054', "arXiv:quant-ph/9806054"),
('279a19fc-331a-4c43-b09b-c38ca21cab0f', 'A Brief Survey Of Quantum Programming Languages', 'Sellinger', 'This article is a brief and subjective survey of quantum programming language research.', NULL, 'a342626c-b086-4ef3-b152-b10262cbfc64', 2004, 'https://link.springer.com/chapter/10.1007/978-3-540-24754-8_1', NULL, "Selinger, P. (2004). A Brief Survey of Quantum Programming Languages. In: Kameyama, Y., Stuckey, P.J. (eds) Functional and Logic Programming. FLOPS 2004. Lecture Notes in Computer Science, vol 2998. Springer, Berlin, Heidelberg. https://doi.org/10.1007/978-3-540-24754-8_1"),
('65234243-d172-4a91-8d03-31c12edf686a', 'A Lambda Calculus for Quantum Computation', 'Tonder', 'The classical lambda calculus may be regarded both as a programming language and as a formal algebraic system for reasoning about computation. It provides a computational model equivalent to the Turing machine, and continues to be of enormous benefit in the classical theory of computation. We propose that quantum computation, like its classical counterpart, may benefit from a version of the lambda calculus suitable for expressing and reasoning about quantum algorithms. In this paper we develop a quantum lambda calculus as an alternative model of quantum computation, which combines some of the benefits of both the quantum Turing machine and the quantum circuit models. The calculus turns out to be closely related to the linear lambda calculi used in the study of Linear Logic. We set up a computational model and an equational proof system for this calculus, and we argue that it is equivalent to the quantum Turing machine.', NULL, '6321c02a-e410-408c-bdde-6a005a964ec7', 2003, NULL, 'http://arxiv.org/abs/quant-ph/0307150', "arXiv:quant-ph/0307150"),
('8eab8ea9-494d-4619-bcc6-61ef51d49c73', 'A functional quantum programming language', 'Altenkirch and Grattage', 'We introduce the language QML, a functional language for quantum computations on finite types. Its design is guided by its categorical semantics: QML programs are interpreted by morphisms in the category FQC of finite quantum computations, which provides a constructive semantics of irreversible quantum computations realisable as quantum gates. QML integrates reversible and irreversible quantum computations in one language, using first order strict linear logic to make weakenings explicit. Strict programs are free from decoherence and hence preserve superpositions and entanglement – which is essential for quantum parallelism.', "e0c3f423-caba-4d9b-b440-fbf14e572d7d", '6d3c21ef-a02f-493e-9daf-7f5bf3e52e12', 2005, NULL, 'http://arxiv.org/abs/quant-ph/0409065', "arXiv:quant-ph/0409065"),
('0cbde824-f089-40da-a6aa-a73c5df7b381', 'Quantum programming languages: survey and bibliography', 'Gay', 'The field of quantum programming languages is developing rapidly and there is a surprisingly large literature. Research in this area includes the design of programming languages for quantum computing, the application of established semantic and logical techniques to the foundations of quantum mechanics, and the design of compilers for quantum programming languages. This article justifies the study of quantum programming languages, presents the basics of quantum computing, surveys the literature in quantum programming languages, and indicates directions for future research.', NULL, '6a693ab9-2148-4512-b593-2b4e6e92ec1a', 2006, "https://www.cambridge.org/core/journals/mathematical-structures-in-computer-science/article/abs/quantum-programming-languages-survey-and-bibliography/80E4ECC8AE770B625A48F2EE28358BA6", NULL, "GAY SJ. Quantum programming languages: survey and bibliography. Mathematical Structures in Computer Science. 2006;16(4):581-600. doi:10.1017/S0960129506005378"),
('3e69ea6b-332d-4f80-a353-47e523e66f17', 'Synthesis of Quantum Logic Circuits', 'Shende et al.', 'The pressure of fundamental limits on classical computation and the promise of exponential speedups from quantum effects have recently brought quantum circuits [10] to the attention of the Electronic Design Automation community [18, 28, 7, 27, 17]. We discuss efficient quantum logic circuits which perform two tasks: (i) implementing generic quantum computations and (ii) initializing quantum registers. In contrast to conventional computing, the latter task is nontrivial because the state-space of an n-qubit register is not finite and contains exponential superpositions of classical bit strings. Our proposed circuits are asymptotically optimal for respective tasks and improve earlier published results by at least a factor of two. The circuits for generic quantum computation constructed by our algorithms are the most efficient known today in terms of the number of difficult gates (quantum controlled-NOTs). They are based on an analogue of the Shannon decomposition of Boolean functions and a new circuit block, quantum multiplexor, that generalizes several known constructions. A theoretical lower bound implies that our circuits cannot be improved by more than a factor of two. We additionally show how to accommodate the severe architectural limitation of using only nearest-neighbor gates that is representative of current implementation technologies. This increases the number of gates by almost an order of magnitude, but preserves the asymptotic optimality of gate counts.', NULL, '81b18b87-6605-4d11-b926-6a02d87f50b6', 2006, NULL, 'https://arxiv.org/abs/quant-ph/0406176', "arXiv:quant-ph/0406176"),
('6d1b76c8-c026-4c49-9f05-a91dfd065d2c', 'Quantum Loop Programs', 'Ying and Feng.', 'Loop is a powerful program construct in classical computation, but its power is still not exploited fully in quantum computation. The exploitation of such power definitely requires a deep understanding of the mechanism of quantum loop programs. In this paper, we introduce a general scheme of quantum loops and describe its computational process. The notions of termination and almost termination are proposed for quantum loops, and the function computed by a quantum loop is defined. To show their expressive power, quantum loops are applied in describing quantum walks. Necessary and sufficient conditions for termination and almost termination of a general quantum loop on any mixed input state are presented. A quantum loop is said to be (almost) terminating if it (almost) terminates on any input state. We show that a quantum loop is almost terminating if and only if it is uniformly almost terminating. It is observed that a small disturbance either on the unitary transformation in the loop body or on the measurement in the loop guard can make any quantum loop (almost) terminating. Moreover, a representation of the function computed by a quantum loop is given in terms of finite summations of matrices. To illustrate the notions and results obtained in this paper, two simplest classes of quantum loop programs, one qubit quantum loops, and two qubit quantum loops defined by controlled gates, are carefully examined.', NULL, '5b3689cb-3746-4af2-9659-fc36fe0d4149', 2007, NULL, 'https://arxiv.org/abs/quant-ph/0605218', "arXiv:quant-ph/0605218"),
-- ('12480736-f25a-4163-80c1-9d7a2dffcf40', 'A reversible programming language and its invertible self-interpreter', 'Yokoyama and Glück.', 'A reversible programming language supports deterministic forward and backward computation. We formalize the programming language Janus and prove its reversibility. We provide a program inverter for the language and implement a self-interpreter that achieves deterministic forward and backward interpretation of Janus programs without using a computation history. As the selfinterpreter is implemented in a reversible language, it is invertible using local program inversion. Many physical phenomena are reversible and we demonstrate the power of Janus by implementing a reversible program for discrete simulation of the Schro ̈dinger wave equation that can be inverted as well as run forward and backward.', NULL, '5b3689cb-3746-4af2-9659-fc36fe0d4149', 2007, 'https://dl.acm.org/doi/10.1145/1244381.1244404', NULL, "Tetsuo Yokoyama and Robert Glück. 2007. A reversible programming language and its invertible self-interpreter. In Proceedings of the 2007 ACM SIGPLAN symposium on Partial evaluation and semantics-based program manipulation (PEPM '07). Association for Computing Machinery, New York, NY, USA, 144–153. https://doi.org/10.1145/1244381.1244404"),
('12480736-f25a-4163-80c1-9d7a2dffcf40', 'A Survey of Quantum Programming Languages: History, Methods, and Tools', 'Sofge', 'Quantum computer programming is emerging as a new subject domain from multidisciplinary research in quantum computing, computer science, mathematics (especially quantum logic, lambda calculi, and linear logic), and engineering attempts to build the first non-trivial quantum computer. This paper briefly surveys the history, methods, and proposed tools for programming quantum computers circa late 2007. It is intended to provide an extensive but non-exhaustive look at work leading up to the current state-of-the-art in quantum computer programming. Further, it is an attempt to analyze the needed programming tools for quantum programmers, to use this analysis to predict the direction in which the field is moving, and to make recommendations for further development of quantum programming language tools.', NULL, NULL, 2007, NULL, 'https://arxiv.org/abs/0804.1118', "arXiv:0804.1118"),
('8378435a-2cf0-43d3-b839-7ec6b7db5140', 'Principles of a reversible programming language', 'Yokoyama et al.', 'The principles of reversible programming languages are explicated and illustrated with reference to the design of a high-level imperative language, Janus. The fundamental properties for such languages include backward as well as forward determinism and reversible updates of data. The unique design features of the language include explicit post-condition assertions, direct access to an inverse semantics and the possibility of clean ({\ie}, garbage-free) computation of injective functions. We suggest the clean simulation of reversible Turing machines as a criterion for computing strength of reversible languages, and demonstrate this for Janus. We show the practicality of the language by implementation of a reversible fast Fourier transform. Our results indicate that the reversible programming paradigm has fundamental properties that are relevant to many different areas of computer science.', NULL, "cd22d006-6c09-4bc0-8926-780d52367b1b", 2008, NULL, 'https://dl.acm.org/doi/10.1145/1366230.1366239', "Tetsuo Yokoyama, Holger Bock Axelsen, and Robert Glück. 2008. Principles of a reversible programming language. In Proceedings of the 5th conference on Computing frontiers (CF '08). Association for Computing Machinery, New York, NY, USA, 43–54. https://doi.org/10.1145/1366230.1366239"),
('588f1770-b85d-46cd-b37f-8449884882ee', 'Quantum algorithm for linear systems of equations', 'Harrow et al.', 'Solving linear systems of equations is a common problem that arises both on its own and as a subroutine in more complex problems: given a matrix A and a vector ~b, find a vector ~x such that A~x = ~b. We consider the case where one doesn’t need to know the solution ~x itself, but rather an approximation of the expectation value of some operator associated with ~x, e.g., ~x†M~x for some matrix M . In this case, when A is sparse, N × N and has condition number κ, classical algorithms  can find ~x and estimate ~x†M~x in O ̃(N √κ) time. Here, we exhibit a quantum algorithm for this task that runs in poly(log N, κ) time, an exponential improvement over the best classical algorithm.', NULL, "cd22d006-6c09-4bc0-8926-780d52367b1b", 2009, 'https://journals.aps.org/prl/abstract/10.1103/PhysRevLett.103.150502', 'https://arxiv.org/abs/0811.3171', "arXiv:0811.3171"),
('46168e30-ba16-44b8-a56e-51f07129f534', 'Construction of a universal quantum computer', 'Lagana et al.', 'We construct a universal quantum computer following Deutsch’s original proposal of a universal quantum Turing machine UQTM . Like Deutsch’s UQTM, our machine can emulate any classical Turing machine and can execute any algorithm that can be implemented in the quantum gate array framework but under the control of a quantum program, and hence is universal. We present the architecture of the machine, which consists of a memory tape and a processor and describe the observables that comprise the registers of the processor and the instruction set, which includes a set of operations that can approximate any unitary operation to any desired accuracy and hence is quantum computationally universal. We present the unitary evolution operators that act on the machine to achieve universal computation and discuss each of them in detail and specify and discuss explicit program halting and concatenation schemes. We define and describe a set of primitive programs in order to demonstrate the universal nature of the machine. These primitive programs facilitate the implementation of more complex algorithms and we demonstrate their use by presenting a program that computes the NAND function, thereby also showing that the machine can compute any classically computable function.', NULL, NULL, 2009, 'https://journals.aps.org/pra/abstract/10.1103/PhysRevA.79.052322', NULL, NULL),
('7f3b9029-cf7b-4270-8b6d-fda102720cae', 'A Reversible Processor Architecture and Its Reversible Logic Design', 'Thomsen et al.', 'We describe the design of a purely reversible computing architecture, Bob, and its instruction set, BobISA. The special features of the design include a simple, yet expressive, locally-invertible instruction set, and fully reversible control logic and address calculation. We have designed an architecture with an ISA that is expressive enough to serve as the target for a compiler from a high-level structured reversible programming language. All-in-all, this paper demonstrates that the design of a complete reversible computing architecture is possible and can serve as the core of a programmable reversible computing system.', NULL, '29eb5feb-79d2-407c-b27b-41adc3d4185d', 2012, 'https://link.springer.com/chapter/10.1007/978-3-642-29517-1_3', NULL, 'Thomsen, M.K., Axelsen, H.B., Glück, R. (2012). A Reversible Processor Architecture and Its Reversible Logic Design. In: De Vos, A., Wille, R. (eds) Reversible Computation. RC 2011. Lecture Notes in Computer Science, vol 7165. Springer, Berlin, Heidelberg. https://doi.org/10.1007/978-3-642-29517-1_3'),
('9af1b00e-5a3d-4cad-81e0-537972d46dc3', 'Defining Quantum Control Flow', 'Ying et al.', 'A remarkable difference between quantum and classical programs is that the control flow of the former can be either classical or quantum. One of the key issues in the theory of quantum programming languages is defining and understanding quantum control flow. A functional language with quantum control flow was defined by Altenkirch and Grattage [Proc. LICS’05, pp. 249-258]. This paper extends their work, and we introduce a general quantum control structure by defining three new quantum program constructs, namely quantum guarded command, quantum choice and quantum recursion. We clarify the relation between quantum choices and probabilistic choices. An interesting difference between quantum recursions with classical control flows and with quantum control flows is revealed.', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2012, 'https://link.springer.com/chapter/10.1007/978-3-642-29517-1_3', 'https://arxiv.org/abs/1209.4379', 'arXiv:1209.4379'),
('d2f428a5-ba3a-4fb5-9882-4018b0e2b33a', 'Quipper: a scalable quantum programming language', 'Green et al.', 'The field of quantum algorithms is vibrant. Still, there is currently a lack of programming languages for describing quantum computation on a practical scale, i.e., not just at the level of toy problems. We address this issue by introducing Quipper, a scalable, expressive, functional, higher-order quantum programming language. Quipper has been used to program a diverse set of non-trivial quantum algorithms, and can generate quantum gate representations using trillions of gates. It is geared towards a model of computation that uses a classical computer to control a quantum device, but is not dependent on any particular model of quantum hardware. Quipper has proven effective and easy to use, and opens the door towards using formal methods to analyze quantum algorithms.', '61e2051d-6ac7-4126-93e6-d512bc300d08', '5d6e7f8a-9b1c-2d3e-4f5a-6b7c8d9e1f2a', 2013, NULL, 'https://dl.acm.org/doi/10.1145/2491956.2462177', "Alexander S. Green, Peter LeFanu Lumsdaine, Neil J. Ross, Peter Selinger, and Benoît Valiron. 2013. Quipper: a scalable quantum programming language. In Proceedings of the 34th ACM SIGPLAN Conference on Programming Language Design and Implementation (PLDI '13). Association for Computing Machinery, New York, NY, USA, 333–342. https://doi.org/10.1145/2491956.2462177"),
('d5055f42-749b-42da-8638-a8edb7e274b0', 'ScaffCC: a framework for compilation and analysis of quantum computing programs', 'JavadiAbhari et al.', 'Quantum computing is a promising technology for highperformance computation, but requires mature toolflows that can map large-scale quantum programs onto targeted hardware. In this paper, we present a scalable compiler for largescale quantum applications, and show the opportunities for reducing compilation and analysis time, as well as output code size. We discuss the similarities and di↵erences between compiling for a quantum computer as opposed to a classical computer, and present a state-of-the-art approach for compilation of classical circuits into quantum circuits. Our work also highlights the importance of high-level quantum compilation for logical circuit translation, quantitative analysis of algorithms, and optimization of circuit lengths.', '6ec32296-2ab0-488a-a2ea-472a28bb272d', '8a9b1c2d-3e4f-5a6b-7c8d-9e1f2a3b4c5d', 2014, NULL, 'https://dl.acm.org/doi/10.1145/2597917.2597939', "Ali JavadiAbhari, Shruti Patil, Daniel Kudrow, Jeff Heckey, Alexey Lvov, Frederic T. Chong, and Margaret Martonosi. 2014. ScaffCC: a framework for compilation and analysis of quantum computing programs. In Proceedings of the 11th ACM Conference on Computing Frontiers (CF '14). Association for Computing Machinery, New York, NY, USA, Article 1, 1–10. https://doi.org/10.1145/2597917.2597939"),
('c496d3e3-8c0c-4ae2-96df-202cdb48730b', 'Quantum Recursion and Second Quantisation', 'Ying', 'This paper introduces a new notion of quantum recursion of which the control flow of the computation is quantum rather than classical as in the notions of recursion considered in the previous studies of quantum programming. A typical example is recursive quantum walks, which are obtained by slightly modifying the construction of the ordinary quantum walks. The operational and denotational semantics of quantum recursions are defined by employing the second quantisation method, and they are proved to be equivalent.', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2014, NULL, 'https://arxiv.org/abs/1405.4443', "arXiv:1405.4443"),
('986db40e-7478-4a42-a2d7-15330cdf9da7', 'Quantum Alternation: Prospects and Problems', 'Bădescu and Panangaden', 'We propose a notion of quantum control in a quantum programming language which permits the superposition of finitely many quantum operations without performing a measurement. This notion takes the form of a conditional construct similar to the if statement in classical programming languages. We show that adding such a quantum if statement to the QPL programming language [11] simplifies the presentation of several quantum algorithms. This motivates the possibility of extending the denotational semantics of QPL to include this form of quantum alternation. We give a denotational semantics for this extension of QPL based on Kraus decompositions rather than on superoperators. Finally, we clarify the relation between quantum alternation and recursion, and discuss the possibility of lifting the semantics defined by Kraus operators to the superoperator semantics defined by Selinger [11].', NULL, '9c05cca1-f423-4342-bcc8-295145900584', 2015, NULL, 'https://arxiv.org/abs/1511.01567', "arXiv:1511.01567"),
('19a04f9b-e46a-4319-a5c3-8d6c1b7c634b', 'Programming the quantum future', 'Valiron et al.', 'THE EARLIEST COMPUTERS, like the ENIAC, were rare and heroically difficult to program. That difficulty stemmed from the requirement that algorithms be expressed in a “vocabulary” suited to the particular hardware available, ranging from function tables for the ENIAC to more conventional arithmetic and movement operations on later machines. Introduction of symbolic programming languages, exemplified by FORTRAN, solved a major difficulty for the next generation of computing devices by enabling specification of an algorithm in a form more suitable for human understanding, then translating this specification to a form executable by the machine. The “programming language” used for such specification bridged a semantic gap between the human and the computing device. It provided two important features: high-level abstractions, taking care of automated bookkeeping, and modularity, making it easier to reason about sub-parts of programs.', NULL, NULL, 2015, NULL, 'https://arxiv.org/abs/1511.01567', "Benoît Valiron, Neil J. Ross, Peter Selinger, D. Scott Alexander, and Jonathan M. Smith. 2015. Programming the quantum future. Commun. ACM 58, 8 (August 2015), 52–61. https://doi.org/10.1145/2699415"),
('f3e191c1-f61f-48e7-bdd1-34abb7eb2669', 'Quantum conditional operations', 'Bislo et al.', 'An essential element of classical computation is the “if-then” construct, that accepts a control bit and an arbitrary gate, and provides conditional execution of the gate depending on the value of the controlling bit. On the other hand, quantum theory prevents the existence of an analogous universal construct accepting a control qubit and an arbitrary quantum gate as its input. Nevertheless, there are controllable sets of quantum gates for which such a construct exists. Here we provide a necessary and sufficient condition for a set of unitary transformations to be controllable, and we give a complete characterization of controllable sets in the two dimensional case. This result reveals an interesting connection between the problem of controllability and the problem of extracting information from an unknown quantum gate while using it.', NULL, NULL, 2016, 'https://journals.aps.org/pra/abstract/10.1103/PhysRevA.94.022340', NULL, NULL),
('765fb4b0-bd09-41ac-9b61-3241b2503e6e', 'QWIRE: a core language for quantum circuits', 'Paykin et al.', 'This paper introduces QWIRE (“choir”), a language for defining quantum circuits and an interface for manipulating them inside of an arbitrary classical host language. QWIRE is minimal—it contains only a few primitives—and sound with respect to the physical properties entailed by quantum mechanics. At the same time, QWIRE is expressive and highly modular due to its relationship with the host language, mirroring the QRAM model of computation that places a quantum computer (controlled by circuits) alongside a classical computer (controlled by the host language). We present QWIRE along with its type system and operational semantics, which we prove is safe and strongly normalizing whenever the host language is. We give circuits a denotational semantics in terms of density matrices. Throughout, we investigate examples that demonstrate the expressive power of QWIRE, including extensions to the host language that (1) expose a general analysis framework for circuits, and (2) provide dependent types.', '9dc7b338-887a-426f-a754-3e2d7588e121', '3c4d5e6f-7a8b-9c1d-2e3f-4a5b6c7d8e9f', 2017, NULL, 'https://dl.acm.org/doi/10.1145/3009837.3009894', "Jennifer Paykin, Robert Rand, and Steve Zdancewic. 2017. QWIRE: a core language for quantum circuits. In Proceedings of the 44th ACM SIGPLAN Symposium on Principles of Programming Languages (POPL '17). Association for Computing Machinery, New York, NY, USA, 846–858. https://doi.org/10.1145/3009837.3009894Jennifer Paykin, Robert Rand, and Steve Zdancewic. 2017. QWIRE: a core language for quantum circuits. SIGPLAN Not. 52, 1 (January 2017), 846–858. https://doi.org/10.1145/3093333.3009894"),
('09f88c1b-65da-41de-a4c3-57d979abaf32', 'From Symmetric Pattern-Matching to Quantum Control', 'Sabry et al.', 'One perspective on quantum algorithms is that they are classical algorithms having access to a special kind of memory with exotic properties. This perspective suggests that, even in the case of quantum algorithms, the control flow notions of sequencing, conditionals, loops, and recursion are entirely classical. There is however, another notion of control flow, that is itself quantum. The notion of quantum conditional expression is reasonably well-understood: the execution of the two expressions becomes itself a superposition of executions. The quantum counterpart of loops and recursion is however not believed to be meaningful in its most general form. In this paper, we argue that, under the right circumstances, a reasonable notion of quantum loops and recursion is possible. To this aim, we first propose a classical, typed, reversible language with lists and fixpoints. We then extend this language to the closed quantum domain (without measurements) by allowing linear combinations of terms and restricting fixpoints to structurally recursive fixpoints whose termination proofs match the proofs of convergence of sequences in infinite-dimensional Hilbert spaces. We additionally give an operational semantics for the quantum language in the spirit of algebraic lambda-calculi and illustrate its expressiveness by modeling several common unitary operations.', NULL, NULL, 2018, NULL, 'https://arxiv.org/abs/1804.00952', "arXiv:1804.00952"),
('b86bf9f9-442d-46ec-be27-ea41c8e69221', 'ProjectQ: An Open Source Software Framework for Quantum Computing', 'Steiger et al.', 'We introduce ProjectQ, an open source software effort for quantum computing. The first release features a compiler framework capable of targeting various types of hardware, a high-performance simulator with emulation capabilities, and compiler plug-ins for circuit drawing and resource estimation. We introduce our Python-embedded domainspecific language, present the features, and provide example implementations for quantum algorithms. The framework allows testing of quantum algorithms through simulation and enables running them on actual quantum hardware using a back-end connecting to the IBM Quantum Experience cloud service. Through extension mechanisms, users can provide back-ends to further quantum hardware, and scientists working on quantum compilation can provide plug-ins for additional compilation, optimization, gate synthesis, and layout strategies.', 'bf05777c-4b00-4783-bf38-dcb1259c023c', '1b2c3d4e-5f6a-7b8c-9d1e-2f3a4b5c6d7e', 2018, NULL, 'https://arxiv.org/abs/1612.08091', "arXiv:1612.08091"),
('34f9da79-3997-409c-a9ff-58b1e1f74153', 'Q#: Enabling Scalable Quantum Computing and Development with a High-level DSL', 'Svore et al.', 'Quantum computing exploits quantum phenomena such as superposition and entanglement to realize a form of parallelism that is not available to traditional computing. It offers the potential of significant computational speed-ups in quantum chemistry, materials science, cryptography, and machine learning. The dominant approach to programming quantum computers is to provide an existing high-level language with libraries that allow for the expression of quantum programs.', 'a6218b37-2ffc-490c-8ae2-d0dd4ce78e88', '6f7a8b9c-1d2e-3f4a-5b6c-7d8e9f1a2b3c', 2018, NULL, 'https://dl.acm.org/doi/10.1145/3183895.3183901', NULL),
('a31e4052-a6ba-486f-b9ca-47a48feed7ae', 'Realizability in the Unitary Sphere', 'Díaz-Caro et al.', 'In this paper we present a semantics for a linear algebraic lambda-calculus based on realizability. This semantics characterizes a notion of unitarity in the system, answering a long standing issue. We derive from the semantics a set of typing rules for a simply-typed linear algebraic lambda-calculus, and show how it extends both to classical and quantum lambda-calculi.', NULL, NULL, 2019, 'https://ieeexplore.ieee.org/document/8785834', NULL, 'A. Díaz-Caro, M. Guillermo, A. Miquel and B. Valiron, "Realizability in the Unitary Sphere," 2019 34th Annual ACM/IEEE Symposium on Logic in Computer Science (LICS), Vancouver, BC, Canada, 2019, pp. 1-13, doi: 10.1109/LICS.2019.8785834.'),
('77f6b15f-26e0-4b6a-b67f-b22de1682b0b', 'Silq: a high-level quantum language with safe uncomputation and intuitive semantics', 'Bichsel et al.', 'Existing quantum languages force the programmer to work at a low level of abstraction leading to unintuitive and cluttered code. A fundamental reason is that dropping temporary values from the program state requires explicitly applying quantum operations that safely uncompute these values. We present Silq, the first quantum language that addresses this challenge by supporting safe, automatic uncomputation. This enables an intuitive semantics that implicitly drops temporary values, as in classical computation. To ensure physicality of Silq’s semantics, its type system leverages novel annotations to reject unphysical programs. Our experimental evaluation demonstrates that Silq programs are not only easier to read and write, but also significantly shorter than equivalent programs in other quantum languages (on average -46% for Q#, -38% for Quipper), while using only half the number of quantum primitives.', '8a9923d3-e28a-436d-a030-62a692c3dbbc', '1b2c3d4e-5f6a-7b8c-9d1e-2f3a4b5c6d7e', 2020, NULL, 'https://dl.acm.org/doi/10.1145/3385412.3386007', 'Benjamin Bichsel, Maximilian Baader, Timon Gehr, and Martin Vechev. 2020. Silq: a high-level quantum language with safe uncomputation and intuitive semantics. In Proceedings of the 41st ACM SIGPLAN Conference on Programming Language Design and Implementation (PLDI 2020). Association for Computing Machinery, New York, NY, USA, 286–300. https://doi.org/10.1145/3385412.3386007'),
('a2fb6acd-c6e3-491f-bf18-cd2d4244d6c8', 't|ket〉: A Retargetable Compiler for NISQ Devices', 'Sivarajah et al.', 'We present t|ket〉, a quantum software development platform produced by Cambridge Quantum Computing Ltd. The heart of t|ket〉 is a language-agnostic optimising compiler designed to generate code for a variety of NISQ devices, which has several features designed to minimise the influence of device error. The compiler has been extensively benchmarked and outperforms most competitors in terms of circuit optimisation and qubit routing.', '30a8cea9-c24b-4706-83aa-eb130561928f', '9072d636-1a98-4485-822e-96307be0b6e8', 2021, NULL, 'https://arxiv.org/abs/2003.10611', 'arXiv:2003.10611'),
('be6590aa-4231-4b01-8fe1-aa91c8a2c2a3', 'Weakly measured while loops: peeking at quantum states', 'Andrés-Martínez et al.', 'A while loop tests a termination condition on every iteration. On a quantum computer, such measurements perturb the evolution of the algorithm. We define a while loop primitive using weak measurements, offering a trade-off between the perturbation caused and the amount of information gained per iteration. This trade-off is adjusted with a parameter set by the programmer. We provide sufficient conditions that let us determine, with arbitrarily high probability, a worst-case estimate of the number of iterations the loop will run for. As an example, we solve Grover’s search problem using a while loop and prove the quadratic quantum speed-up is maintained.', NULL, '9072d636-1a98-4485-822e-96307be0b6e8', 2022, NULL, 'https://arxiv.org/abs/2009.08832', 'arXiv:2009.08832'),
('2ec868ec-55bd-4454-a159-31064ad6c418', 'Conventions for Quantum Pseudocode', 'Knill', 'A few conventions for thinking about and writing quantum pseudocode are proposed. The conventions can be used for presenting any quantum algorithm down to the lowest level and are consistent with a quantum random access machine (QRAM) model for quantum computing. In principle a formal version of quantum pseudocode could be used in a future extension of a conventional language.', NULL, NULL, 1996, NULL, 'http://arxiv.org/abs/2211.02559', 'arXiv:2211.02559'),
('c00d36c4-fb9e-48bc-97d2-c6209df27ca9', 'Qiwi: A Beginner Friendly Quantum Language', 'Pal and Ghosh', 'Acknowledging the inter-disciplinary aspect of quantum computing, there is a need to make quantum programming more accessible for its fast-growing community. With the advent of quantum computers with hundreds of qubits designing circuits manually is infeasible. Most current languages are low-level or involve a steep learning curve or lack control. Thus we propose a quantum programming language (QPL) that allows for high-level abstractions with intuitive syntax while still allowing users to directly construct circuits. High-level languages decrease user control and caution leading to sub-optimal circuits. To prevent this, Qiwi allows for dead qubit elimination and has dynamically sized data types. We also introduce a mechanism to let the compiler decide the most optimal among several overloaded function definitions, based on statements following the call. Moreover, this work also presents circuits for if outside the control family of gates and a control for loop on quantum data.', '02e1e060-ebca-4fb4-a2fe-9f4a4d90b22a', '9f1a2b3c-4d5e-6f7a-8b9c-1d2e3f4a5b6c', 2022, NULL, 'https://dl.acm.org/doi/10.1145/3563768.3563959', 'Abhinandan Pal and Anubhab Ghosh. 2022. Qiwi: A Beginner Friendly Quantum Language. In Companion Proceedings of the 2022 ACM SIGPLAN International Conference on Systems, Programming, Languages, and Applications: Software for Humanity (SPLASH Companion 2022). Association for Computing Machinery, New York, NY, USA, 78–80. https://doi.org/10.1145/3563768.3563959'),
('4509e978-0981-4117-ac5e-8613ca0725b5', 'Semantics of quantum programming languages: Classical control, quantum control', 'Valiron', 'This chapter is devoted to a discussion on the semantics of quantum programming languages. We will discuss two main paradigms: the usual, standard co-processor model, and more exotic models based on quantum superposition of executions. We will discuss how these two systems can –or cannot– be unified, and how this relates to languages.', '02e1e060-ebca-4fb4-a2fe-9f4a4d90b22a', '9f1a2b3c-4d5e-6f7a-8b9c-1d2e3f4a5b6c', 2022, 'https://www.sciencedirect.com/science/article/abs/pii/S2352220822000438?via%3Dihub', NULL, 'Benoît Valiron,Semantics of quantum programming languages: Classical control, quantum control,Journal of Logical and Algebraic Methods in Programming,Volume 128,2022,100790,ISSN 2352-2208,https://doi.org/10.1016/j.jlamp.2022.100790.(https://www.sciencedirect.com/science/article/pii/S2352220822000438)'),
('299b13e5-0623-4f40-bfb9-c2bd9fe6298f', 'Tower: data structures in Quantum superposition', 'Yuan and Carbin', 'Emerging quantum algorithms for problems such as element distinctness, subset sum, and closest pair demonstrate computational advantages by relying on abstract data structures. Practically realizing such an algorithm as a program for a quantum computer requires an efficient implementation of the data structure whose operations correspond to unitary operators that manipulate quantum superpositions of data. To correctly operate in superposition, an implementation must satisfy three properties Ð reversibility, history independence, and bounded-time execution. Standard implementations, such as the representation of an abstract set as a hash table, fail these properties, calling for tools to develop specialized implementations. In this work, we present Core Tower, the first language for quantum programming with random-access memory. Core Tower enables the developer to implement data structures as pointer-based, linked data. It features a reversible semantics enabling every valid program to be translated to a unitary quantum circuit. We present Boson, the first memory allocator that supports reversible, history-independent, and constanttime dynamic memory allocation in quantum superposition. We also present Tower, a language for quantum programming with recursively defined data structures. Tower features a type system that bounds all recursion using classical parameters as is necessary for a program to execute on a quantum computer. Using Tower, we implement Ground, the first quantum library of data structures, including lists, stacks, queues, strings, and sets. We provide the first executable implementation of sets that satisfies all three mandated properties of reversibility, history independence, and bounded-time execution.', '1abc58fc-0274-42f1-9732-a5782d4a5b12', 'ac4dc2d4-1281-4eec-8c55-770188ef31dd', 2022, NULL, 'https://dl.acm.org/doi/10.1145/3563297', 'Charles Yuan and Michael Carbin. 2022. Tower: data structures in Quantum superposition. Proc. ACM Program. Lang. 6, OOPSLA2, Article 134 (October 2022), 30 pages. https://doi.org/10.1145/3563297'),
('dbfb507d-e3c5-45ad-9df5-3e74c6b3c42f', 'Twist: sound reasoning for purity and entanglement in Quantum programs', 'Yuan et al.', 'Quantum programming languages enable developers to implement algorithms for quantum computers that promise computational breakthroughs in classically intractable tasks. Programming quantum computers requires awareness of entanglement, the phenomenon in which measurement outcomes of qubits are correlated. Entanglement can determine the correctness of algorithms and suitability of programming patterns. In this work, we formalize purity as a central tool for automating reasoning about entanglement in quantum programs. A pure expression is one whose evaluation is unaffected by the measurement outcomes of qubits that it does not own, implying freedom from entanglement with any other expression in the computation. We present Twist, the first language that features a type system for sound reasoning about purity. The type system enables the developer to identify pure expressions using type annotations. Twist also features purity assertion operators that state the absence of entanglement in the output of quantum gates. To soundly check these assertions, Twist uses a combination of static analysis and runtime verification. We evaluate Twist’s type system and analyses on a benchmark suite of quantum programs in simulation, demonstrating that Twist can express quantum algorithms, catch programming errors in them, and support programs that existing languages disallow, while incurring runtime verification overhead of less than 3.5%.', 'a9406d45-8799-466a-a582-677d73402aa7', 'ac4dc2d4-1281-4eec-8c55-770188ef31dd', 2022, NULL, 'https://dl.acm.org/doi/10.1145/3498691', 'Charles Yuan, Christopher McNally, and Michael Carbin. 2022. Twist: sound reasoning for purity and entanglement in Quantum programs. Proc. ACM Program. Lang. 6, POPL, Article 30 (January 2022), 32 pages. https://doi.org/10.1145/3498691'),
('3918916a-9797-4aa3-bdee-02412468fc6c', 'isQ: An Integrated Software Stack for Quantum Programming', 'Guo et al.', 'We introduce isQ, a new software stack for quantum programming in an imperative programming language, also named isQ. The aim of isQ is to make programmers write quantum programs as conveniently as possible. In particular, 1) the isQ language and its compiler contain many useful features, including but not limited to classical control flow, such as recursion, decomposition of self-defined unitary gates, and oracle programming and its circuit realization. 2) To make it flexible, an isQ program can be compiled into several different kinds of intermediate representation and assemblies, including QIR, eQASM, OpenQASM 3.0, and QCIS (specially tailored for the superconducting quantum hardware at the University of Science and Technology of China). 3) Besides interfacing isQ with real superconducting hardware, a QIR simulator is also developed for the demonstration and testing of isQ programs. The isQ software stack encompasses abundant compiler optimizations of high-level quantum programs. To realize it, a distinct multilevel intermediate representation (MLIR) dialect name isQ-IR is proposed.', 'dbb651c6-7e65-491a-80e4-4dbb7e20e54d', '5b3689cb-3746-4af2-9659-fc36fe0d4149', 2023, NULL, 'https://ieeexplore.ieee.org/document/10129229', 'J. Guo et al., "isQ: An Integrated Software Stack for Quantum Programming," in IEEE Transactions on Quantum Engineering, vol. 4, pp. 1-16, 2023, Art no. 2500116, doi: 10.1109/TQE.2023.3275868.'),
('ed9d528b-0bc4-41d4-b1fb-86104265bdb4', 'Qunity: A Unified Language for Quantum and Classical Computing', 'Voichick et al.', 'We introduce Qunity, a new quantum programming language designed to treat quantum computing as a natural generalization of classical computing. Qunity presents a unified syntax where familiar programming constructs can have both quantum and classical effects. For example, one can use sum types to implement the direct sum of linear operators, exception-handling syntax to implement projective measurements, and aliasing to induce entanglement. Further, Qunity takes advantage of the overlooked bqp subroutine theorem, allowing one to construct reversible subroutines from irreversible quantum algorithms through the uncomputation of “garbage” outputs. Unlike existing languages that enable quantum aspects with separate add-ons (like a classical language with quantum gates bolted on), Qunity provides a unified syntax and a novel denotational semantics that guarantees that programs are quantum mechanically valid. We present Qunity’s syntax, type system, and denotational semantics, showing how it can cleanly express several quantum algorithms. We also detail how Qunity can be compiled into a low-level qubit circuit language like OpenQasm, proving the realizability of our design.', 'c62158ad-451d-4a12-8857-881f7eac4f6b', '7e8f9a1b-2c3d-4e5f-6a7b-8c9d1e2f3a4b', 2023, NULL, 'https://dl.acm.org/doi/10.1145/3571225', 'Finn Voichick, Liyi Li, Robert Rand, and Michael Hicks. 2023. Qunity: A Unified Language for Quantum and Classical Computing. Proc. ACM Program. Lang. 7, POPL, Article 32 (January 2023), 31 pages. https://doi.org/10.1145/3571225'),
('a7f40d56-3ae6-49cc-b4d8-4f51d1a81304', 'Quantum Random Access Stored-Program Machines', 'Wang and Ying', 'Random access machines (RAMs) and random access stored-program machines (RASPs) are models of computing that are closer to the architecture of real-world computers than Turing machines (TMs). They are also convenient in complexity analysis of algorithms. The relationships between RAMs, RASPs and TMs are well-studied. However, clear relationships between their quantum counterparts are still missing in the literature. We fill in this gap by formally defining the models of quantum random access machines (QRAMs) and quantum random access stored-program machines (QRASPs) and clarifying the relationships between QRAMs, QRASPs and quantum Turing machines (QTMs). In particular, we show that P ⊆ EQRAMP ⊆ EQP ⊆ BQP = BQRAMP, where EQRAMP and BQRAMP stand for the sets of problems that can be solved by polynomial-time QRAMs with certainty and bounded-error, respectively. At the heart of our proof, is a standardisation of QTM with an extended halting scheme, which is of independent interest.', NULL, '5b3689cb-3746-4af2-9659-fc36fe0d4149', 2023, NULL, 'https://arxiv.org/abs/2003.03514', 'arXiv:2003.03514'),
('fa8047f6-3e8e-4afd-920e-9358e26e404d', 'A Case for Synthesis of Recursive Quantum Unitary Programs', 'Deng et al.', 'Quantum programs are notoriously difficult to code and verify due to unintuitive quantum knowledge associated with quantum programming. Automated tools relieving the tedium and errors associated with low-level quantum details would hence be highly desirable. In this paper, we initiate the study of program synthesis for quantum unitary programs that recursively define a family of unitary circuits for different input sizes, which are widely used in existing quantum programming languages. Specifically, we present QSynth, the first quantum program synthesis framework, including a new inductive quantum programming language, its specification, a sound logic for reasoning, and an encoding of the reasoning procedure into SMT instances. By leveraging existing SMT solvers, QSynth successfully synthesizes 10 quantum unitary programs including quantum arithmetic programs, quantum eigenvalue inversion, quantum teleportation and Quantum Fourier Transformation, which can be readily transpiled to executable programs on major quantum platforms, e.g., Q#, IBM Qiskit, and AWS Braket.', NULL, '7e8f9a1b-2c3d-4e5f-6a7b-8c9d1e2f3a4b', 2024, NULL, 'https://dl.acm.org/doi/10.1145/3632901', 'Haowei Deng, Runzhou Tao, Yuxiang Peng, and Xiaodi Wu. 2024. A Case for Synthesis of Recursive Quantum Unitary Programs. Proc. ACM Program. Lang. 8, POPL, Article 59 (January 2024), 30 pages. https://doi.org/10.1145/3632901'),
('e7389e82-af8a-48d0-a2a8-c9df85573a70', 'Quantum computing with Qiskit', 'Javadi-Abhari et al.', 'We describe Qiskit, a software development kit for quantum information science. We discuss the key design decisions that have shaped its development, and examine the software architecture and its core components. We demonstrate an end-to-end workflow for solving a problem in condensed matter physics on a quantum computer that serves to highlight some of Qiskit’s capabilities, for example the representation and optimization of circuits at various abstraction levels, its scalability and retargetability to new gates, and the use of quantum-classical computations via dynamic circuits. Lastly, we discuss some of the ecosystem of tools and plugins that extend Qiskit for various tasks, and the future ahead.', '84f32d82-9892-4248-8d59-922535dbf8bc', 'f9eef6ae-93fb-488f-af2d-c56e5b20f5e8', 2024, NULL, 'https://arxiv.org/abs/2405.08810', 'arXiv:2405.08810'),
('bcf3417a-f774-4c6f-bad2-0f43ec007de3', 'Verification of Recursively Defined Quantum Circuits', 'Ying and Zhang', 'Recursive techniques have recently been introduced into quantum programming so that a variety of large quantum circuits and algorithms can be elegantly and economically programmed. In this paper, we present a proof system for formal verification of the correctness of recursively defined quantum circuits. The soundness and (relative) completeness of the proof system are established. To demonstrating its effectiveness, a series of application examples of the proof system are given, including (multi-qubit) controlled gates, a quantum circuit generating (multi-qubit) GHZ (Greenberger-HorneZeilinger) states, recursive definition of quantum Fourier transform, quantum state preparation, and quantum random-access memories (QRAM).', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2024, NULL, 'http://arxiv.org/abs/2404.05934', 'arXiv:2404.05934'),
('ea70f58a-e1c0-4470-adb6-963c5fd980ff', 'The T-Complexity Costs of Error Correction for Control Flow in Quantum Computation', 'Yuan and Carbin', 'Numerous quantum algorithms require the use of quantum error correction to overcome the intrinsic unreliability of physical qubits. However, quantum error correction imposes a unique performance bottleneck, known as T -complexity, that can make an implementation of an algorithm as a quantum program run more slowly than on idealized hardware. In this work, we identify that programming abstractions for control flow, such as the quantum if-statement, can introduce polynomial increases in the T -complexity of a program. If not mitigated, this slowdown can diminish the computational advantage of a quantum algorithm. To enable reasoning about the costs of control flow, we present a cost model that a developer can use to accurately analyze the T -complexity of a program under quantum error correction and pinpoint the sources of slowdown. To enable the mitigation of these costs, we present a set of program-level optimizations that a developer can use to rewrite a program to reduce its T -complexity, predict the T -complexity of the optimized program using the cost model, and then compile it to an efficient circuit via a straightforward strategy. We implement the program-level optimizations in Spire, an extension of the Tower quantum compiler. Using a set of 11 benchmark programs that use control flow, we empirically show that the cost model is accurate, and that Spire’s optimizations recover programs that are asymptotically efficient, meaning their runtime T -complexity under error correction is equal to their time complexity on idealized hardware. Our results show that optimizing a program before it is compiled to a circuit can yield better results than compiling the program to an inefficient circuit and then invoking a quantum circuit optimizer found in prior work. For our benchmarks, only 2 of 8 tested quantum circuit optimizers recover circuits with asymptotically efficient T -complexity. Compared to these 2 optimizers, Spire uses 54×–2400× less compile time.', NULL, 'ac4dc2d4-1281-4eec-8c55-770188ef31dd', 2024, NULL, 'https://dl.acm.org/doi/10.1145/3656397', 'Charles Yuan and Michael Carbin. 2024. The T-Complexity Costs of Error Correction for Control Flow in Quantum Computation. Proc. ACM Program. Lang. 8, PLDI, Article 167 (June 2024), 26 pages. https://doi.org/10.1145/3656397'),
('055708bf-65ba-4399-ad13-4a923e80e8c0', 'Quantum Control Machine', 'Yuan et al.', 'Quantum algorithms for tasks such as factorization, search, and simulation rely on control flow such as branching and iteration that depends on the value of data in superposition. High-level programming abstractions for  control flow, such as switches, loops, higher-order functions, and continuations, are ubiquitous in classical  languages. By contrast, many quantum languages do not provide high-level abstractions for control flow in  superposition, and instead require the use of hardware-level logic gates to implement such control flow.  The reason for this gap is that whereas a classical computer supports control flow abstractions using a  program counter that can depend on data, the typical architecture of a quantum computer does not analogously  provide a program counter that can depend on data in superposition. As a result, the complete set of control  flow abstractions that can be correctly realized on a quantum computer has not yet been established.  In this work, we provide a complete characterization of the properties of control flow abstractions that are  correctly realizable on a quantum computer. First, we prove that even on a quantum computer whose program  counter exists in superposition, one cannot correctly realize control flow in quantum algorithms by lifting the  classical conditional jump instruction to work in superposition. This theorem denies the ability to directly lift  general abstractions for control flow such as the λ-calculus from classical to quantum programming.  In response, we present the necessary and sufficient conditions for control flow to be correctly realizable  on a quantum computer. We introduce the quantum control machine, an instruction set architecture featuring  a conditional jump that is restricted to satisfy these conditions. We show how this design enables a developer  to correctly express control flow in quantum algorithms using a program counter in place of logic gates.', 'd2505189-b62a-44a7-a0b1-d64662cc0a35', 'ac4dc2d4-1281-4eec-8c55-770188ef31dd', 2024, NULL, 'https://arxiv.org/abs/2304.15000', 'arXiv:2304.15000'),
('354acb25-7257-48b1-aee8-72d61a5f515a', 'Resource-Aware Quantum Programming with General Recursion and Quantum Control', 'Chardonnet et al.', 'This paper introduces the hybrid quantum language with general recursion Hyrql, driven towards resource-analysis. By design, Hyrql does not require the specification of an initial set of quantum gates. Hence, it is well amenable towards a generic cost analysis, unlike languages that use different sets of quantum gates, which yield quantum circuits of distinct complexity. Regarding resource-analysis, we show how to relate the runtime of an expressive fragment of Hyrql programs with the size of the corresponding quantum circuits. We also manage to capture the class of functions computable in quantum polynomial time, which, by Yao’s Theorem, corresponds to families of circuits of polynomial size. Consequently, this result paves the way for the use of termination and runtime-analysis techniques designed for classical programs to guarantee bounds on the size of quantum circuits.', NULL, '31b7c242-64d5-4d2a-9ffa-830fdebd8902', 2025, NULL, 'https://arxiv.org/abs/2510.20452', 'arXiv:2510.20452'),
('e102ad98-b51e-484c-a5f0-cfc1527dbb8d', 'GUPPY: Pythonic Quantum-Classical Programming', 'Koch et al.', 'We present ongoing work on Guppy, a domain-specific language embedded in Python that allows users to write high-level hybrid quantum programs with complex control flow in Pythonic syntax, aiming to run them on actual quantum hardware.', '65aadc12-52f2-4205-b4cd-2e2c7570f089', '31b7c242-64d5-4d2a-9ffa-830fdebd8902', 2025, NULL, 'https://arxiv.org/abs/2510.12582', 'arXiv:2510.12582'),
('1ef26a3c-79e3-4b7c-a171-e277900e8219', 'Compositional Quantum Control Flow with Efficient Compilation in Qunity', 'Mints et al.', 'Most existing quantum programming languages are based on the quantum circuit model of computation,  as higher-level abstractions are particularly challenging to implement—especially ones relating to quantum  control flow. The Qunity language, proposed by Voichick et al., offered such an abstraction in the form of  a quantum control construct, with great care taken to ensure that the resulting language is still realizable.  However, Qunity lacked a working implementation, and the originally proposed compilation procedure was  very inefficient, with even simple quantum algorithms compiling to unreasonably large circuits.  In this work, we focus on the efficient compilation of high-level quantum control flow constructs, using  Qunity as our starting point. We introduce a wider range of abstractions on top of Qunity’s core language that  offer compelling trade-offs compared to its existing control construct. We create a complete implementation of  a Qunity compiler, which converts high-level Qunity code into the quantum assembly language OpenQASM 3.  We develop optimization techniques for multiple stages of the Qunity compilation procedure, including both  low-level circuit optimizations as well as methods that consider the high-level structure of a Qunity program,  greatly reducing the number of qubits and gates used by the compiler.', 'c62158ad-451d-4a12-8857-881f7eac4f6b', 'ad7903ba-fce3-4966-8ede-558c0d10f3c4', 2025, NULL, 'https://dl.acm.org/doi/10.1145/3763056', 'Mikhail Mints, Finn Voichick, Leonidas Lampropoulos, and Robert Rand. 2025. Compositional Quantum Control Flow with Efficient Compilation in Qunity. Proc. ACM Program. Lang. 9, OOPSLA2, Article 278 (October 2025), 27 pages. https://doi.org/10.1145/3763056'),
('c206debe-d3cf-4963-90c0-4ec46250c79f', 'Quantum Register Machine: Efficient Implementation of Quantum Recursive Programs', 'Zhang and Ying', 'MQuantum recursive programming has been recently introduced for describing sophisticated and complicated quantum algorithms in a compact and elegant way. However, implementation of quantum recursion involves intricate interplay between quantum control flow and recursive procedure calls. In this paper, we aim at resolving this fundamental challenge and develop a series of techniques to efficiently implement quantum recursive programs. Our main contributions include:  (1) We propose a notion of quantum register machine, the first quantum architecture (including an instruction set) that provides instruction-level support for quantum control flow and recursive procedure calls at the same time. (2) Based on quantum register machine, we describe the first comprehensive implementation process of quantum recursive programs, including the compilation, the partial evaluation of quantum control flow, and the execution on the quantum register machine. (3) As a bonus, our efficient implementation of quantum recursive programs also offers automatic parallelisation of quantum algorithms. For implementing certain quantum algorithmic subroutine, like the widely used quantum multiplexor, we can even obtain exponential parallel speed-up (over the straightforward implementation) from this automatic parallelisation. This demonstrates that quantum recursive programming can be win-win for both modularity of programs and efficiency of their implementation.', NULL, '9c1d2e4f-6a3b-5c7d-8e9f-1a5c9d3e7f2a', 2025, NULL, 'https://dl.acm.org/doi/10.1145/3729283', 'Zhicheng Zhang and Mingsheng Ying. 2025. Quantum Register Machine: Efficient Implementation of Quantum Recursive Programs. Proc. ACM Program. Lang. 9, PLDI, Article 180 (June 2025), 26 pages. https://doi.org/10.1145/3729283'),
('26bfda1b-21db-4fad-8219-8ab581db0004', 'Quantum Control and General Recursion beyond the Unitary Case', 'Barsse et al.', 'Coherent control, aka quantum control, is a central concept in quantum computing that is attracting increasing attention from both the  quantum foundations and quantum software communities. Defining coherent control in the presence of recursion and measurement  has long been known to be a major challenge. In particular, no-go  results have been established for standard semantical domains like  completely positive maps. We address this problem by introducing  the first quantum programming language with recursion that allows for the coherent control of arbitrary quantum operations. We  equip this language with both an operational and a denotational  semantics that we prove to be adequate. To design these semantics,  we show that combining coherent control, recursion, and measurement crucially requires describing the evolution of subprograms  in the absence of input. To address this, the operational semantics  takes into account a default evolution branch, while the denotational semantics uses the concept of coherent quantum operation,  based on vacuum extensions. We strengthen the validity of our approach by developing an observational equivalence: two programs  are equivalent if their probability of termination is the same in any  context. The denotational semantics is shown to be fully abstract  with respect to this observational equivalence.', NULL, '31b7c242-64d5-4d2a-9ffa-830fdebd8902', 2026, NULL, 'https://arxiv.org/abs/2507.10466', 'arXiv:2507.10466'),
('ebab0c37-ea6a-4233-bd7e-bf8ccc7f7b71', 'Quantum Circuits Are Just a Phase', 'Heunen et al.', 'Quantum programs today are written at a low level of abstraction—quantum circuits akin to assembly  languages—and the unitary parts of even advanced quantum programming languages essentially function as  circuit description languages. This state of affairs impedes scalability, clarity, and support for higher-level  reasoning. More abstract and expressive quantum programming constructs are needed.  To this end, we introduce a simple syntax for generating unitaries from “just a phase”; we combine a  (global) phase operation that captures phase shifts with a quantum analogue of the “if let” construct that  captures subspace selection via pattern matching. This minimal language lifts the focus from gates to eigendecomposition, conjugation, and controlled unitaries; common building blocks in quantum algorithm design.  We demonstrate several aspects of the expressive power of our language in several ways. Firstly, we  establish that our representation is universal by deriving a universal quantum gate set. Secondly, we show  that important quantum algorithms can be expressed naturally and concisely, including Grover’s search  algorithm, Hamiltonian simulation, Quantum Fourier Transform, Quantum Signal Processing, and the Quantum  Eigenvalue Transformation. Furthermore, we give clean denotational semantics grounded in categorical  quantum mechanics. Finally, we implement a prototype compiler that efficiently translates terms of our  language to quantum circuits, and prove that it is sound with respect to these semantics. Collectively, these  contributions show that this construct offers a principled and practical step toward more abstract and structured  quantum programming.', NULL, 'ac4dc2d4-1281-4eec-8c55-770188ef31dd', 2026, NULL, 'https://arxiv.org/abs/2507.11676', 'arXiv:2507.11676');


